"use client"

import { useState, useEffect } from "react";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { MapPin, Radio, ShieldAlert, Navigation, LocateFixed, Radar } from "lucide-react";
import Image from "next/image";
import { PlaceHolderImages } from "@/lib/placeholder-images";
import { cn } from "@/lib/utils";

export default function ExplorePage() {
  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isWatching, setIsWatching] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined" || !navigator.geolocation) {
      setError("Geolocation is not supported");
      return;
    }

    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        setLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        });
        setIsWatching(true);
      },
      (err) => {
        setError(err.message);
        setIsWatching(false);
      },
      { enableHighAccuracy: true }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  const mapImage = PlaceHolderImages.find(img => img.id === 'kosovo-map')?.imageUrl || "https://picsum.photos/seed/map/1200/1200";

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 relative overflow-hidden">
      {/* Interactive Map Background */}
      <div className="absolute inset-0 z-0">
        <Image 
          src={mapImage}
          alt="Map" 
          fill 
          className="object-cover opacity-60 contrast-125 scale-110"
          priority
          data-ai-hint="satellite map"
        />
        
        {/* Dynamic Scan Line Effect */}
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-accent/10 to-transparent h-24 w-full animate-scan z-10" />
        
        {/* Animated Radar Hotspots */}
        {[
          { t: '25%', l: '35%', label: 'Mobile Unit', color: 'bg-red-500', border: 'border-red-500' },
          { t: '40%', l: '65%', label: 'Fixed Speed Cam', color: 'bg-orange-500', border: 'border-orange-500' },
          { t: '65%', l: '45%', label: 'Highway Patrol', color: 'bg-red-500', border: 'border-red-500' }
        ].map((point, i) => (
          <div key={i} className="absolute z-20" style={{ top: point.t, left: point.l }}>
            <div className="relative flex items-center justify-center">
              <div className={cn("absolute w-12 h-12 rounded-full border animate-ping", point.border, "opacity-40")} />
              <div className={cn("w-4 h-4 rounded-full shadow-lg", point.color)} />
              <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 whitespace-nowrap text-[8px] font-black uppercase bg-black/80 px-1.5 py-0.5 rounded border border-white/10 text-white">
                {point.label}
              </div>
            </div>
          </div>
        ))}

        {/* User Location Marker */}
        {location && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-30">
            <div className="relative">
              <div className="w-24 h-24 rounded-full bg-accent/20 border border-accent/40 flex items-center justify-center animate-pulse absolute inset-0 -m-6" />
              <div className="w-12 h-12 rounded-full bg-accent/40 border-2 border-accent flex items-center justify-center shadow-[0_0_30px_theme(colors.accent.DEFAULT)] backdrop-blur-sm">
                <Navigation className="w-6 h-6 text-background fill-background rotate-45" />
              </div>
              <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-accent text-background text-[10px] font-black px-3 py-1 rounded-full whitespace-nowrap shadow-xl">
                YOU
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Map UI Overlays */}
      <div className="relative z-40 p-6 flex flex-col h-full gap-4">
        <div className="flex justify-between items-start">
          <div className="glass p-4 rounded-2xl border-white/10 flex flex-col gap-1 w-56 shadow-2xl backdrop-blur-xl bg-black/40">
            <div className="flex items-center gap-2 mb-1">
              <Radar className={cn("w-4 h-4 text-accent", isWatching && "animate-spin")} />
              <span className="text-[10px] font-black text-accent uppercase tracking-widest">DRIVE RADAR LIVE</span>
            </div>
            {location ? (
              <div className="space-y-1">
                <p className="text-[10px] font-bold text-muted-foreground uppercase leading-none">GPS Position</p>
                <p className="text-xs font-mono font-bold italic text-white leading-none">
                  {location.lat.toFixed(6)}° N<br/>
                  {location.lng.toFixed(6)}° E
                </p>
              </div>
            ) : (
              <p className="text-xs font-bold text-red-400 animate-pulse">
                {error ? `GPS Error: ${error}` : "Acquiring link..."}
              </p>
            )}
          </div>
          <Button 
            size="icon" 
            variant="outline" 
            onClick={() => window.location.reload()}
            className="rounded-2xl glass border-white/10 w-12 h-12 shadow-2xl hover:bg-accent/20 backdrop-blur-xl bg-black/40"
          >
            <LocateFixed className="w-5 h-5 text-accent" />
          </Button>
        </div>

        {/* Nearby Alerts Feed */}
        <div className="mt-auto space-y-3 mb-6">
          <div className="glass border-red-500/40 rounded-3xl p-5 shadow-[0_0_50px_rgba(239,68,68,0.3)] animate-pulse border-2 backdrop-blur-xl bg-black/60">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-red-500/20 flex items-center justify-center border border-red-500/50">
                <ShieldAlert className="w-7 h-7 text-red-500" />
              </div>
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <h3 className="text-base font-black italic uppercase tracking-tighter text-red-500">DANGER ZONE</h3>
                  <Badge className="bg-red-500 text-white font-bold text-[8px] h-4">CRITICAL</Badge>
                </div>
                <p className="text-sm font-bold opacity-90 leading-tight">Police Mobile Unit detected within 2km</p>
                <p className="text-[10px] font-bold uppercase opacity-50 mt-1">Ferizaj-Prishtinë Zone</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}